def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        accumulated = 0
        for n in range(1, 10):
            if n % 2 == 0:
                base = np.sin(n * ratio * np.pi)
            else:
                base = np.cos(n * ratio * np.pi)
            weight = (1 / (n ** 1.5)) * (0.9 + 0.1 * (n % 3))
            increment = weight * abs(base) * (1 - ratio) ** n
            accumulated += increment
            if accumulated > 0.8:
                score += accumulated * 1.2
                accumulated = 0
            elif accumulated < 0.2 and n == 9:
                score += accumulated * 0.5
        if score == 0:
            score = 0.1
        leftover_ratio = (capacity - item) / capacity
        if leftover_ratio <= 0.05:
            score *= 2.8
        elif leftover_ratio <= 0.15:
            score *= 1.7
        elif leftover_ratio <= 0.25:
            score *= 1.2
        else:
            score *= 0.65
        mod_factors = {3: 0, 5: 0, 7: 0}
        for mod in mod_factors.keys():
            if int(capacity) % mod == 0:
                mod_factors[mod] = 1
        if mod_factors[3] and mod_factors[7]:
            score -= 0.15 * (capacity / 22)
        elif mod_factors[5]:
            score -= 0.09 * (capacity / 18)
        elif mod_factors[3]:
            score -= 0.07 * (capacity / 13)
        elif mod_factors[7]:
            score -= 0.05 * (capacity / 28)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 7):
            delta = abs(capacity - item * k)
            thresh = 0.02 * capacity * k
            if delta < thresh:
                penalty += 0.3 * k ** 1.2
            elif delta < 3 * thresh:
                penalty += 0.12 * k
            else:
                penalty -= 0.06 * k
            if k % 2 == 0 and delta < thresh:
                penalty += 0.05 * k
        score += penalty
        if score < 0.05:
            score = 0.05
        if score > 1.8:
            for m in range(1, 6):
                div_val = capacity / m
                tolerance = 0.025 * div_val
                if abs(div_val - item) < tolerance:
                    multiplier = 1 + 0.07 * m
                    if m % 2 == 0:
                        multiplier += 0.03
                    score *= multiplier
        balances = []
        for p in range(1, 5):
            factor = ((capacity - p * item) / capacity) * (1 - ratio**p)
            balances.append(factor)
        score += sum(balances) * 0.1
        priorities[i] = score
    return priorities
